  /**
   * Capture a test-mode authorization
   * @description <p>Capture a test-mode authorization.</p>
   */
  PostTestHelpersIssuingAuthorizationsAuthorizationCapture: {
    parameters: {
      path: {
        authorization: string;
      };
    };
    requestBody?: {
      content: {
        'application/x-www-form-urlencoded': {
          /** @description The amount to capture from the authorization. If not provided, the full amount of the authorization will be captured. This amount is in the authorization currency and in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal). */
          capture_amount?: number;
          /** @description Whether to close the authorization after capture. Defaults to true. Set to false to enable multi-capture flows. */
          close_authorization?: boolean;
          /** @description Specifies which fields in the response should be expanded. */
          expand?: string[];
          /**
           * purchase_details_specs
           * @description Additional purchase information that is optionally provided by the merchant.
           */
          purchase_details?: {
            /** fleet_specs */
            fleet?: {
              /** fleet_cardholder_prompt_data_specs */
              cardholder_prompt_data?: {
                driver_id?: string;
                odometer?: number;
                unspecified_id?: string;
                user_id?: string;
                vehicle_number?: string;
              };
              /** @enum {string} */
              purchase_type?:
                | 'fuel_and_non_fuel_purchase'
                | 'fuel_purchase'
                | 'non_fuel_purchase';
              /** fleet_reported_breakdown_specs */
              reported_breakdown?: {
                /** fleet_reported_breakdown_fuel_specs */
                fuel?: {
                  /** Format: decimal */
                  gross_amount_decimal?: string;
                };
                /** fleet_reported_breakdown_non_fuel_specs */
                non_fuel?: {
                  /** Format: decimal */
                  gross_amount_decimal?: string;
                };
                /** fleet_reported_breakdown_tax_specs */
                tax?: {
                  /** Format: decimal */
                  local_amount_decimal?: string;
                  /** Format: decimal */
                  national_amount_decimal?: string;
                };
              };
              /** @enum {string} */
              service_type?:
                | 'full_service'
                | 'non_fuel_transaction'
                | 'self_service';
            };
            /** flight_specs */
            flight?: {
              /** Format: unix-time */
              departure_at?: number;
              passenger_name?: string;
              refundable?: boolean;
              segments?: {
                arrival_airport_code?: string;
                carrier?: string;
                departure_airport_code?: string;
                flight_number?: string;
                service_class?: string;
                stopover_allowed?: boolean;
              }[];
              travel_agency?: string;
            };
            /** fuel_specs */
            fuel?: {
              industry_product_code?: string;
              /** Format: decimal */
              quantity_decimal?: string;
              /** @enum {string} */
              type?:
                | 'diesel'
                | 'other'
                | 'unleaded_plus'
                | 'unleaded_regular'
                | 'unleaded_super';
              /** @enum {string} */
              unit?:
                | 'charging_minute'
                | 'imperial_gallon'
                | 'kilogram'
                | 'kilowatt_hour'
                | 'liter'
                | 'other'
                | 'pound'
                | 'us_gallon';
              /** Format: decimal */
              unit_cost_decimal?: string;
            };
            /** lodging_specs */
            lodging?: {
              /** Format: unix-time */
              check_in_at?: number;
              nights?: number;
            };
            receipt?: {
              description?: string;
              /** Format: decimal */
              quantity?: string;
              total?: number;
              unit_cost?: number;
            }[];
            reference?: string;
          };
        };
      };
    };
    responses: {
      /** @description Successful response. */
      200: {
        content: {
          'application/json': components['schemas']['issuing.authorization'];
        };
      };
      /** @description Error response. */
      default: {
        content: {
          'application/json': components['schemas']['error'];
        };
      };
    };
  };
